const decimal expectedTax = expectedSubtotal * 0.09m;       // 22.275 → 22.28
const decimal expectedTotal = expectedSubtotal + expectedTax;

Assert.AreEqual(expectedSubtotal, order.TotalAmount, "Subtotal mismatch");
Assert.AreEqual(expectedTax, order.TaxAmount, "Tax mismatch");
Assert.AreEqual(expectedTotal, order.GrandTotal, "Grand total mismatch");
```

